+import type { AnyColumn } from '~/column.ts';
+import { SQL, sql, type SQLWrapper } from '../sql.ts';
+
+export type WindowFrameBoundary =
+	| { readonly kind: 'unbounded preceding' }
+	| { readonly kind: 'current row' }
+	| { readonly kind: 'unbounded following' }
+	| { readonly kind: 'preceding'; readonly value: number }
+	| { readonly kind: 'following'; readonly value: number };
+
+export const unboundedPreceding: WindowFrameBoundary = { kind: 'unbounded preceding' };
+export const currentRow: WindowFrameBoundary = { kind: 'current row' };
+export const unboundedFollowing: WindowFrameBoundary = { kind: 'unbounded following' };
+
+function assertFrameOffset(name: 'preceding' | 'following', value: number): void {
+	if (!Number.isInteger(value) || value < 0) {
+		throw new Error(`${name}() requires a non-negative integer, received ${value}`);
+	}
+}
+
+export function preceding(value: number): WindowFrameBoundary {
+	assertFrameOffset('preceding', value);
+	return { kind: 'preceding', value };
+}
+
+export function following(value: number): WindowFrameBoundary {
+	assertFrameOffset('following', value);
+	return { kind: 'following', value };
+}
+
+export interface WindowFrame {
+	readonly type: 'rows' | 'range';
+	readonly from: WindowFrameBoundary;
+	readonly to: WindowFrameBoundary;
+}
+
+function boundaryPosition(boundary: WindowFrameBoundary): number {
+	switch (boundary.kind) {
+		case 'unbounded preceding': return -Infinity;
+		case 'preceding': return -boundary.value;
+		case 'current row': return 0;
+		case 'following': return boundary.value;
+		case 'unbounded following': return Infinity;
+	}
+}
+
+function createFrame(type: WindowFrame['type'], { from, to }: { from: WindowFrameBoundary; to: WindowFrameBoundary }): WindowFrame {
+	if (boundaryPosition(from) > boundaryPosition(to)) {
+		throw new Error('Window frame "from" boundary cannot be ordered after its "to" boundary');
+	}
+	return { type, from, to };
+}
+
+export function rows(boundaries: { from: WindowFrameBoundary; to: WindowFrameBoundary }): WindowFrame {
+	return createFrame('rows', boundaries);
+}
+
+export function range(boundaries: { from: WindowFrameBoundary; to: WindowFrameBoundary }): WindowFrame {
+	return createFrame('range', boundaries);
+}
+
+export interface WindowSpec {
+	partitionBy?: SQLWrapper | SQLWrapper[];
+	orderBy?: SQLWrapper | SQLWrapper[];
+	frame?: WindowFrame;
+}
+
+function buildBoundary(boundary: WindowFrameBoundary): SQL {
+	switch (boundary.kind) {
+		case 'unbounded preceding': return sql.raw('unbounded preceding');
+		case 'current row': return sql.raw('current row');
+		case 'unbounded following': return sql.raw('unbounded following');
+		case 'preceding': return sql`${sql.raw(String(boundary.value))} preceding`;
+		case 'following': return sql`${sql.raw(String(boundary.value))} following`;
+	}
+}
+
+/** @internal */
+export function buildWindowSpec(spec: WindowSpec = {}): SQL {
+	const parts: SQL[] = [];
+	if (spec.partitionBy) {
+		parts.push(sql`partition by ${sql.join(Array.isArray(spec.partitionBy) ? spec.partitionBy : [spec.partitionBy], sql`, `)}`);
+	}
+	if (spec.orderBy) {
+		parts.push(sql`order by ${sql.join(Array.isArray(spec.orderBy) ? spec.orderBy : [spec.orderBy], sql`, `)}`);
+	}
+	if (spec.frame) {
+		parts.push(sql`${sql.raw(spec.frame.type)} between ${buildBoundary(spec.frame.from)} and ${buildBoundary(spec.frame.to)}`);
+	}
+	return sql.join(parts, sql` `);
+}
+
+export class WindowFunctionBuilder<T> extends SQL<T> {
+	constructor(expression: SQL<T>) {
+		super(expression.queryChunks);
+	}
+
+	over(spec: WindowSpec): SQL<T>;
+	over(windowName: string): SQL<T>;
+	over(spec: WindowSpec | string = {}): SQL<T> {
+		return typeof spec === 'string'
+			? sql`${this} over ${sql.identifier(spec)}` as SQL<T>
+			: sql`${this} over (${buildWindowSpec(spec)})` as SQL<T>;
+	}
+}
+
+type WindowValue<T extends SQLWrapper> = T extends AnyColumn ? T['_']['data'] : T extends SQL<infer TValue> ? TValue : unknown;
+
+function windowFunction<T>(name: string, args: SQL[]): WindowFunctionBuilder<T> {
+	return new WindowFunctionBuilder(sql`${sql.raw(name)}(${sql.join(args, sql`, `)})` as SQL<T>);
+}
+
+function positiveInteger(name: 'ntile' | 'nthValue', value: number): void {
+	if (!Number.isInteger(value) || value <= 0) {
+		throw new Error(`${name}() requires a positive integer, received ${value}`);
+	}
+}
+
+const inlineInteger = (value: number) => sql.raw(String(value));
+
+export const rowNumber = (): WindowFunctionBuilder<number> => windowFunction('row_number', []);
+export const rank = (): WindowFunctionBuilder<number> => windowFunction('rank', []);
+export const denseRank = (): WindowFunctionBuilder<number> => windowFunction('dense_rank', []);
+export const percentRank = (): WindowFunctionBuilder<number> => windowFunction('percent_rank', []);
+export const cumeDist = (): WindowFunctionBuilder<number> => windowFunction('cume_dist', []);
+
+export function ntile(buckets: number): WindowFunctionBuilder<number> {
+	positiveInteger('ntile', buckets);
+	return windowFunction('ntile', [inlineInteger(buckets)]);
+}
+
+function valueFunction<T extends SQLWrapper>(name: string, expression: T, positionalArguments: number[] = []): WindowFunctionBuilder<WindowValue<T> | null> {
+	return windowFunction(name, [expression.getSQL(), ...positionalArguments.map(inlineInteger)]);
+}
+
+export function lag<T extends SQLWrapper>(expression: T, offset?: number, defaultValue?: unknown): WindowFunctionBuilder<WindowValue<T> | null>;
+export function lag<T extends SQLWrapper>(expression: T, offset: number | undefined, defaultValue: unknown): WindowFunctionBuilder<WindowValue<T>>;
+export function lag<T extends SQLWrapper>(expression: T, offset?: number, defaultValue?: unknown): WindowFunctionBuilder<WindowValue<T> | null> {
+	const args = [expression.getSQL()];
+	if (offset !== undefined || defaultValue !== undefined) args.push(inlineInteger(offset ?? 1));
+	if (defaultValue !== undefined) args.push(sql`${defaultValue}`);
+	return windowFunction('lag', args);
+}
+
+export function lead<T extends SQLWrapper>(expression: T, offset?: number, defaultValue?: unknown): WindowFunctionBuilder<WindowValue<T> | null>;
+export function lead<T extends SQLWrapper>(expression: T, offset: number | undefined, defaultValue: unknown): WindowFunctionBuilder<WindowValue<T>>;
+export function lead<T extends SQLWrapper>(expression: T, offset?: number, defaultValue?: unknown): WindowFunctionBuilder<WindowValue<T> | null> {
+	const args = [expression.getSQL()];
+	if (offset !== undefined || defaultValue !== undefined) args.push(inlineInteger(offset ?? 1));
+	if (defaultValue !== undefined) args.push(sql`${defaultValue}`);
+	return windowFunction('lead', args);
+}
+
+export const firstValue = <T extends SQLWrapper>(expression: T) => valueFunction('first_value', expression);
+export const lastValue = <T extends SQLWrapper>(expression: T) => valueFunction('last_value', expression);
+
+export function nthValue<T extends SQLWrapper>(expression: T, nth: number): WindowFunctionBuilder<WindowValue<T> | null> {
+	positiveInteger('nthValue', nth);
+	return valueFunction('nth_value', expression, [nth]);
+}
+
+export const windowSum = (expression: SQLWrapper): WindowFunctionBuilder<string | null> => windowFunction('sum', [expression.getSQL()]);
+export const windowAvg = (expression: SQLWrapper): WindowFunctionBuilder<string | null> => windowFunction('avg', [expression.getSQL()]);
+export const windowMin = <T extends SQLWrapper>(expression: T): WindowFunctionBuilder<WindowValue<T> | null> => windowFunction('min', [expression.getSQL()]);
+export const windowMax = <T extends SQLWrapper>(expression: T): WindowFunctionBuilder<WindowValue<T> | null> => windowFunction('max', [expression.getSQL()]);
+export const windowCount = (expression?: SQLWrapper): WindowFunctionBuilder<number> => windowFunction('count', [expression ? expression.getSQL() : sql.raw('*')]);
