+import { expect, test } from 'vitest';
+
+import { integer, PgDialect, pgTable } from '~/pg-core/index.ts';
+import { PgSelectBuilder } from '~/pg-core/query-builders/select.ts';
+import {
+	cumeDist,
+	currentRow,
+	denseRank,
+	following,
+	firstValue,
+	lag,
+	lead,
+	lastValue,
+	nthValue,
+	ntile,
+	percentRank,
+	range,
+	rank,
+	rowNumber,
+	rows,
+	unboundedFollowing,
+	unboundedPreceding,
+	windowAvg,
+	windowCount,
+	windowMax,
+	windowMin,
+	windowSum,
+} from '~/sql/index.ts';
+
+const users = pgTable('users', { id: integer('id') });
+const dialect = new PgDialect();
+
+const toSQL = (expression: ReturnType<typeof rowNumber>) => dialect.sqlToQuery(expression.over({}));
+
+test('window helpers compile to SQL names and inline numeric positions', () => {
+	const expressions = [
+		rowNumber(), rank(), denseRank(), ntile(2), percentRank(), cumeDist(),
+		lag(users.id, 0), lead(users.id, 0, 42), firstValue(users.id), lastValue(users.id), nthValue(users.id, 3),
+		windowSum(users.id), windowAvg(users.id), windowMin(users.id), windowMax(users.id), windowCount(),
+	];
+
+	const queries = expressions.map((expression) => dialect.sqlToQuery(expression.over({ orderBy: users.id })));
+	expect(queries.map((query) => query.sql)).toEqual([
+		'row_number() over (order by "users"."id")',
+		'rank() over (order by "users"."id")',
+		'dense_rank() over (order by "users"."id")',
+		'ntile(2) over (order by "users"."id")',
+		'percent_rank() over (order by "users"."id")',
+		'cume_dist() over (order by "users"."id")',
+		'lag("users"."id", 0) over (order by "users"."id")',
+		'lead("users"."id", 0, $1) over (order by "users"."id")',
+		'first_value("users"."id") over (order by "users"."id")',
+		'last_value("users"."id") over (order by "users"."id")',
+		'nth_value("users"."id", 3) over (order by "users"."id")',
+		'sum("users"."id") over (order by "users"."id")',
+		'avg("users"."id") over (order by "users"."id")',
+		'min("users"."id") over (order by "users"."id")',
+		'max("users"."id") over (order by "users"."id")',
+		'count(*) over (order by "users"."id")',
+	]);
+	expect(queries[7]!.params).toEqual([42]);
+	expect(toSQL(rowNumber()).sql).toBe('row_number() over ()');
+});
+
+test('window specs compile frames and named definitions before order by', () => {
+	const query = new PgSelectBuilder({
+		fields: { rank: rowNumber().over('rank_window') },
+		session: undefined,
